import React, { useState, useEffect, useContext } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { ThemeContext } from '../../context/ThemeContext';
import Modal from '../Modal/Modal';

const Navbar = ({ isAuthenticated, handleLogout, userRole }) => {
    const navigate = useNavigate();
    const location = useLocation();
    const { theme, toggleTheme } = useContext(ThemeContext);
    const [hoveredMenu, setHoveredMenu] = useState(null);
    const [logoHovered, setLogoHovered] = useState(false);
    const [isMobile, setIsMobile] = useState(window.innerWidth < 768);
    const [showLogoutModal, setShowLogoutModal] = useState(false);
    const [showSuccessModal, setShowSuccessModal] = useState(false);

    const isDark = theme === 'dark';

    useEffect(() => {
        const handleResize = () => {
            setIsMobile(window.innerWidth < 768);
        };
        window.addEventListener('resize', handleResize);
        return () => window.removeEventListener('resize', handleResize);
    }, []);

    const navigateTo = (path) => {
        window.scrollTo({ top: 0, behavior: 'instant' });
        navigate(path);
    };

    const handleLogoutClick = () => {
        setShowLogoutModal(true);
    };

    const confirmLogout = () => {
        setShowLogoutModal(false);
        setShowSuccessModal(true);
        setTimeout(() => {
            handleLogout();
        }, 2000);
    };

    const getMenuStyle = (menuPath) => ({
        background: 'none', 
        border: 'none',
        color: hoveredMenu === menuPath || location.pathname === menuPath || (menuPath === '/home' && location.pathname === '/') ? '#ea580c' : (isDark ? '#fff' : '#1c1917'),
        fontWeight: '700', 
        cursor: 'pointer', 
        fontSize: isMobile ? '18px' : '14px', 
        transition: 'all 0.3s ease',
        padding: '12px 0',
        position: 'relative',
        letterSpacing: '0.3px',
        width: isMobile ? '100%' : 'auto',
        textAlign: isMobile ? 'center' : 'left'
    });

    const getMobileNavItems = () => {
        const baseItems = [
            { path: '/home', icon: '🏠', label: 'Beranda' },
            { path: '/eksplorasi', icon: '🔍', label: 'Cari' },
        ];
        if (!isAuthenticated) {
            baseItems.push({ path: '/login', icon: '🔑', label: 'Login' });
        } else if (userRole === 'Pelamar') {
            baseItems.push(
                { path: '/favorit', icon: '⭐', label: 'Favorit' },
                { path: '/status-lamaran', icon: '📋', label: 'Status' },
                { path: '/profile', icon: '👤', label: 'Profil' },
            );
        } else if (userRole === 'Perusahaan') {
            baseItems.push(
                { path: '/hrd/dashboard', icon: '📊', label: 'Dashboard' },
                { path: '/hrd/branding', icon: '🏢', label: 'Branding' },
            );
        } else if (userRole === 'Admin') {
            baseItems.push(
                { path: '/admin/dashboard', icon: '⚙️', label: 'Admin' },
            );
        }
        if (isAuthenticated) {
            baseItems.push({ path: 'logout', icon: '🚪', label: 'Keluar', isLogout: true });
        }
        return baseItems;
    };

    return (
        <>
            <Modal
                isOpen={showLogoutModal}
                onClose={() => setShowLogoutModal(false)}
                title="Konfirmasi Logout"
                message="Apakah Anda yakin ingin keluar dari akun Anda?"
                type="warning"
                onConfirm={confirmLogout}
            />

            <Modal
                isOpen={showSuccessModal}
                onClose={() => setShowSuccessModal(false)}
                title="Berhasil Logout"
                message="Anda telah berhasil keluar dari akun. Sampai jumpa kembali!"
                type="success"
            />

            <div style={{
                position: 'fixed',
                bottom: isMobile ? '16px' : 'auto',
                top: isMobile ? 'auto' : '16px',
                left: 0,
                right: 0,
                display: 'flex',
                justifyContent: 'center',
                zIndex: 1000,
                pointerEvents: 'none'
            }}>
                {/* Logo Section */}
                <div 
                    onClick={() => navigateTo('/')} 
                    style={{ 
                        cursor: 'pointer',
                        transition: 'all 0.3s ease',
                        display: 'flex',
                        alignItems: 'center',
                        gap: isMobile ? '6px' : '8px'
                    }}
                    onMouseEnter={(e) => {
                        if (!isMobile) {
                            setLogoHovered(true);
                            e.currentTarget.style.transform = 'scale(1.02)';
                        }
                    }}
                    onMouseLeave={(e) => {
                        if (!isMobile) {
                            setLogoHovered(false);
                            e.currentTarget.style.transform = 'scale(1)';
                        }
                    }}
                >
                    <div style={{
                        width: isMobile ? '32px' : '36px',
                        height: isMobile ? '32px' : '36px',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        background: `linear-gradient(135deg, #ea580c, #f59e0b)`,
                        borderRadius: '10px',
                        transform: !isMobile && logoHovered ? 'rotate(5deg) scale(1.05)' : 'rotate(0deg) scale(1)',
                        transition: 'all 0.3s ease',
                        boxShadow: !isMobile && logoHovered ? '0 4px 15px rgba(234, 88, 12, 0.4)' : 'none'
                    }}>
                        <span style={{
                            fontSize: isMobile ? '16px' : '18px',
                            fontWeight: '900',
                            color: '#fff'
                        }}>
                            ⚡
                        </span>
                    </div>

                    <div>
                        <h2 style={{ 
                            color: isDark ? '#fef3c7' : '#1c1917', 
                            margin: 0, 
                            fontSize: isMobile ? '18px' : '22px',
                            fontWeight: '800',
                            letterSpacing: '-0.5px',
                            display: 'flex',
                            alignItems: 'center',
                            gap: '2px',
                            flexWrap: 'wrap'
                        }}>
                            <span style={{ 
                                background: 'linear-gradient(135deg, #ea580c, #f59e0b)',
                                backgroundClip: 'text',
                                WebkitBackgroundClip: 'text',
                                color: 'transparent'
                            }}>
                                Pasukan
                            </span>
                            <span style={{ color: '#ea580c' }}>Yerus</span>
                            <span style={{ color: isDark ? '#fef3c7' : '#1c1917' }}>Solo</span>
                        </h2>
                        {!isMobile && (
                            <div style={{
                                fontSize: '8px',
                                letterSpacing: '1px',
                                color: '#ea580c',
                                textTransform: 'uppercase',
                                fontWeight: '700',
                                marginTop: '2px',
                                opacity: logoHovered ? 1 : 0.7,
                                transition: 'opacity 0.3s ease'
                            }}>
                                #1 Portal Karir
                            </div>
                        )}
                    </div>
                </div>

                {/* Desktop Menu */}
                <div className="nav-menu" style={{ 
                    display: isMobile ? 'none' : 'flex', 
                    alignItems: 'center',
                    gap: isMobile ? '4px' : '6px',
                    background: isDark ? 'rgba(12, 10, 9, 0.85)' : 'rgba(245, 245, 244, 0.85)',
                    backdropFilter: 'blur(16px)',
                    WebkitBackdropFilter: 'blur(16px)',
                    border: `1px solid ${isDark ? 'rgba(38,38,38,0.5)' : 'rgba(229,229,229,0.5)'}`,
                    borderRadius: '60px',
                    overflow: 'hidden',
                    padding: isMobile ? '6px 8px' : '8px 12px',
                    boxShadow: isDark
                        ? '0 8px 32px rgba(0,0,0,0.4)'
                        : '0 8px 32px rgba(0,0,0,0.1)',
                }}>
                    <button 
                        style={getMenuStyle('/home')} 
                        onClick={() => navigateTo('/home')} 
                        onMouseEnter={() => setHoveredMenu('/home')} 
                        onMouseLeave={() => setHoveredMenu(null)}
                    >
                        Beranda
                        {(location.pathname === '/' || location.pathname === '/home') && (
                            <span style={{
                                position: 'absolute',
                                bottom: '0',
                                left: '0',
                                width: '100%',
                                height: '2px',
                                background: '#ea580c',
                                borderRadius: '2px'
                            }} />
                        )}
                    </button>
                    <button 
                        style={getMenuStyle('/eksplorasi')} 
                        onClick={() => navigateTo('/eksplorasi')} 
                        onMouseEnter={() => setHoveredMenu('/eksplorasi')} 
                        onMouseLeave={() => setHoveredMenu(null)}
                    >
                        Lowongan
                        {location.pathname === '/eksplorasi' && (
                            <span style={{
                                position: 'absolute',
                                bottom: '0',
                                left: '0',
                                width: '100%',
                                height: '2px',
                                background: '#ea580c',
                                borderRadius: '2px'
                            }} />
                        )}
                    </button>

                    {isAuthenticated && userRole === 'Pelamar' && (
                        <>
                            <button 
                                style={getMenuStyle('/profile')} 
                                onClick={() => navigateTo('/profile')} 
                                onMouseEnter={() => setHoveredMenu('/profile')} 
                                onMouseLeave={() => setHoveredMenu(null)}
                            >
                                Profil
                                {location.pathname === '/profile' && (
                                    <span style={{
                                        position: 'absolute',
                                        bottom: '0',
                                        left: '0',
                                        width: '100%',
                                        height: '2px',
                                        background: '#ea580c',
                                        borderRadius: '2px'
                                    }} />
                                )}
                            </button>
                            <button 
                                style={getMenuStyle('/favorit')} 
                                onClick={() => navigateTo('/favorit')} 
                                onMouseEnter={() => setHoveredMenu('/favorit')} 
                                onMouseLeave={() => setHoveredMenu(null)}
                            >
                                Favorit
                                {location.pathname === '/favorit' && (
                                    <span style={{
                                        position: 'absolute',
                                        bottom: '0',
                                        left: '0',
                                        width: '100%',
                                        height: '2px',
                                        background: '#ea580c',
                                        borderRadius: '2px'
                                    }} />
                                )}
                            </button>
                            <button 
                                style={getMenuStyle('/status-lamaran')} 
                                onClick={() => navigateTo('/status-lamaran')} 
                                onMouseEnter={() => setHoveredMenu('/status-lamaran')} 
                                onMouseLeave={() => setHoveredMenu(null)}
                            >
                                Status
                                {location.pathname === '/status-lamaran' && (
                                    <span style={{
                                        position: 'absolute',
                                        bottom: '0',
                                        left: '0',
                                        width: '100%',
                                        height: '2px',
                                        background: '#ea580c',
                                        borderRadius: '2px'
                                    }} />
                                )}
                            </button>
                        </>
                    )}

                    {isAuthenticated && userRole === 'Perusahaan' && (
                        <>
                            <button 
                                style={getMenuStyle('/hrd/dashboard')} 
                                onClick={() => navigateTo('/hrd/dashboard')} 
                                onMouseEnter={() => setHoveredMenu('/hrd/dashboard')} 
                                onMouseLeave={() => setHoveredMenu(null)}
                            >
                                Dashboard
                                {location.pathname === '/hrd/dashboard' && (
                                    <span style={{
                                        position: 'absolute',
                                        bottom: '0',
                                        left: '0',
                                        width: '100%',
                                        height: '2px',
                                        background: '#ea580c',
                                        borderRadius: '2px'
                                    }} />
                                )}
                            </button>
                            <button 
                                style={getMenuStyle('/hrd/branding')} 
                                onClick={() => navigateTo('/hrd/branding')} 
                                onMouseEnter={() => setHoveredMenu('/hrd/branding')} 
                                onMouseLeave={() => setHoveredMenu(null)}
                            >
                                Branding
                                {location.pathname === '/hrd/branding' && (
                                    <span style={{
                                        position: 'absolute',
                                        bottom: '0',
                                        left: '0',
                                        width: '100%',
                                        height: '2px',
                                        background: '#ea580c',
                                        borderRadius: '2px'
                                    }} />
                                )}
                            </button>
                        </>
                    )}

                    {isAuthenticated && userRole === 'Admin' && (
                        <button 
                            style={getMenuStyle('/admin/dashboard')} 
                            onClick={() => navigateTo('/admin/dashboard')} 
                            onMouseEnter={() => setHoveredMenu('/admin/dashboard')} 
                            onMouseLeave={() => setHoveredMenu(null)}
                        >
                            Admin Panel
                            {location.pathname === '/admin/dashboard' && (
                                <span style={{
                                    position: 'absolute',
                                    bottom: '0',
                                    left: '0',
                                    width: '100%',
                                    height: '2px',
                                    background: '#ea580c',
                                    borderRadius: '2px'
                                }} />
                            )}
                        </button>
                    )}
                </div>
            </div>

            {/* Mobile Bottom Navigation */}
            {isMobile && (
                <div style={{
                    position: 'fixed',
                    bottom: 0,
                    left: 0,
                    right: 0,
                    background: isDark ? '#0c0a09' : '#ffffff',
                    borderTop: `1px solid ${isDark ? '#262626' : '#e5e5e5'}`,
                    display: 'flex',
                    justifyContent: 'space-around',
                    alignItems: 'center',
                    padding: '6px 0 calc(6px + env(safe-area-inset-bottom, 0px))',
                    zIndex: 1000,
                    boxShadow: isDark ? '0 -2px 20px rgba(0,0,0,0.3)' : '0 -2px 20px rgba(0,0,0,0.08)'
                }}>
                    {getMobileNavItems().map(item => (
                        <button 
                            key={item.path}
                            onClick={() => item.isLogout ? handleLogoutClick() : navigateTo(item.path)}
                            style={{
                                background: 'none',
                                border: 'none',
                                cursor: 'pointer',
                                display: 'flex',
                                flexDirection: 'column',
                                alignItems: 'center',
                                gap: '2px',
                                padding: '4px 8px',
                                color: item.isLogout ? '#ef4444' : (location.pathname === item.path ? '#ea580c' : (isDark ? '#a8a29e' : '#78716c')),
                                transition: 'all 0.2s ease',
                                position: 'relative',
                                minWidth: '48px',
                                flex: 1,
                                maxWidth: '80px'
                            }}
                        >
                            <span style={{ fontSize: '20px', lineHeight: 1 }}>{item.icon}</span>
                            <span style={{ 
                                fontSize: '10px', 
                                fontWeight: item.isLogout ? '700' : (location.pathname === item.path ? '700' : '500'),
                                whiteSpace: 'nowrap'
                            }}>
                                {item.label}
                            </span>
                            {!item.isLogout && location.pathname === item.path && (
                                <span style={{
                                    position: 'absolute',
                                    top: '-6px',
                                    left: '50%',
                                    transform: 'translateX(-50%)',
                                    width: '20px',
                                    height: '3px',
                                    background: '#ea580c',
                                    borderRadius: '3px'
                                }} />
                            )}
                        </button>
                    ))}
                </div>
            )}

            <style>{`
                @media (max-width: 768px) {
                    .nav-menu { display: none !important; }
                    body { padding-bottom: 60px !important; }
                }
                @media (max-width: 480px) {
                    nav { padding: 12px 3% !important; }
                }
            `}</style>
        </>
    );
};

export default Navbar;
